// n8n Expression — access trigger data in downstream nodes
// (Written in the n8n Expression Editor, not standalone JS)

// From a Webhook trigger:
{{ $json.body.message }}             // POST body field
{{ $json.headers['x-api-key'] }}     // request header

// From an HTTP Request node (previous node result):
{{ $node['HTTP Request'].json.data[0].name }}

// From the AI Agent output:
{{ $node['AI Agent'].json.output }}

// HTTP Request node used as an agent tool
// Configure via UI — shown as pseudoconfig for clarity
{
  "method": "GET",
  "url": "https://api.weather.example.com/current",
  "qs": {
    "city": "={{ $fromAI('city', 'The city to look up') }}"
  },
  "headers": {
    "Authorization": "Bearer {{ $env.WEATHER_API_KEY }}"
  }
}

// $fromAI() is n8n's built-in helper that tells the AI Agent
// how to populate this parameter — it becomes a tool argument

// Custom Tool node attached to the AI Agent (n8n Code node as a tool)
// This runs when the agent decides to use the "get_ticket_status" tool
const ticketId = $input.item.json.ticketId;

// Simulate a database lookup
const statuses = {
  'TKT-001': 'In Progress',
  'TKT-002': 'Resolved',
  'TKT-003': 'Pending',
};

return {
  json: {
    ticketId,
    status: statuses[ticketId] ?? 'Unknown',
    updatedAt: new Date().toISOString(),
  },
};

// Memory Manager node configuration (set via the UI; shown as JSON for reference)
{
  "sessionId": "={{ $json.userId }}",
  "contextWindowLength": 10,          // keep last 10 message pairs
  "memoryType": "Window Buffer Memory"
  // or "Summary Buffer Memory" for longer sessions
}

// The AI Agent node automatically reads from and writes to the Memory Manager
// You do not wire them manually — just attach Memory Manager to the Agent node

// Code node (JavaScript) — pre-process data before passing to AI Agent
// Runs server-side in n8n's sandboxed Node.js runtime
const items = $input.all();

return items.map(item => {
  const data = item.json;
  return {
    json: {
      // Trim long bodies to avoid token overuse
      body: data.body?.slice(0, 2000) ?? '',
      subject: data.subject,
      ticketId: data.id,
      categories: ['Billing', 'Technical', 'General', 'Refund'],
    },
  };
});

// Constructing a dynamic prompt in n8n expressions
// (used in the "User Message" field of the AI Agent node)

Summarise the following support ticket and suggest a resolution category.

Ticket ID: {{ $json.ticketId }}
Subject: {{ $json.subject }}
Body:
{{ $json.body }}

Available categories: {{ $json.categories.join(', ') }}
Respond in JSON: { "summary": "...", "category": "..." }

// Calling a sub-workflow from within a workflow
// Use the "Execute Workflow" node — configure via UI:
// - Workflow to call: select by name
// - Input data: pass from current node
// - Wait for completion: true (synchronous) or false (fire-and-forget)

// In the sub-workflow, the Execute Workflow Trigger node exposes:
{{ $json.inputData }}       // data passed from the parent

// Return data from the sub-workflow:
// Use the Respond to Webhook node or set an output item
return [{ json: { result: 'processed', count: 42 } }]

// Error workflow — triggered when any node in another workflow throws
// Set via: Workflow Settings → Error Workflow

// $execution.error gives you:
{
  "message": "Request failed with status code 429",
  "node": { "name": "HTTP Request", "type": "n8n-nodes-base.httpRequest" },
  "stack": "...",
  "timestamp": "2026-07-01T21:00:00.000Z"
}

// Typical error workflow steps:
// 1. Check $execution.error.message
// 2. Send alert to Slack / PagerDuty
// 3. Optionally retry: use IF node to decide based on error type

// Batch-processing workflow pattern
// 1. Trigger: Schedule (daily at 2AM) or webhook with bulk payload
// 2. Split in Batches node: process 10 items at a time
// 3. AI Agent (per batch) → structured output
// 4. Aggregate results → write to database

// Split in Batches node settings (UI):
// - Batch Size: 10
// - Options → Reset: false (maintain counter across executions)

// After the AI Agent:
// The Aggregate node merges all batches back into one array
// so the next node (e.g., Google Sheets) receives all results at once

// Inside the AI Agent user message for batch:
For each of these {{ $json.items.length }} items, classify sentiment:
{{ $json.items.map((it, i) => `${i+1}. ${it.text}`).join('\n') }}

Return a JSON array: [{ "index": 1, "sentiment": "positive" }, ...]

// RAG workflow with n8n Vector Store nodes
// (Requires n8n version 1.29+ with Vector Store support)

// Step 1 — Ingest documents (run once or on schedule):
// Trigger → Read PDF/CSV → Text Splitter → Embeddings → Vector Store (Insert)

// Step 2 — Query (per user message):
// Webhook Trigger → AI Agent (with Vector Store Tool attached)

// Vector Store Tool configuration (n8n UI):
{
  "mode": "Retrieve Documents (As Tool For AI Agent)",
  "vectorStore": "In-Memory / Pinecone / Qdrant / PGVector",
  "topK": 5,
  "toolName": "knowledge_base",
  "toolDescription": "Search the company knowledge base for policy and procedure documents"
}

// The AI Agent receives retrieved chunks as tool results
// and can cite them in its response
